'use client';

import type { ToasterProps } from 'sonner';
import { useComponentConfig } from '../config-provider/context';
import SonnerUI from './SonnerUI';

const Sonner = (props: ToasterProps) => {
  const config = useComponentConfig('sonner');

  const mergedProps = {
    ...config,
    ...props
  };

  return <SonnerUI {...mergedProps} />;
};

Sonner.displayName = 'Sonner';

export default Sonner;

'use client';

import type { CSSProperties } from 'react';
import { useTheme } from 'next-themes';
import type { ToasterProps } from 'sonner';
import { Toaster as Sonner } from 'sonner';
import { cn } from '@/lib/utils';

const css = {
  '--border-radius': 'var(--radius - 2px)',
  '--error-text': 'hsl(var(--destructive))',
  '--info-text': 'hsl(var(--info))',
  '--normal-bg': 'hsl(var(--background))',
  '--normal-border': 'hsl(var(--border))',
  '--normal-text': 'hsl(var(--foreground))',
  '--success-text': 'hsl(var(--success))',
  '--warning-text': 'hsl(var(--warning))',
  'pointerEvents': 'auto'
};

const toastVariants
  = '!border-border !bg-card !text-card-foreground !shadow-[0_4px_6px_-1px_rgb(0_0_0_/_0.1),_0_2px_4px_-2px_rgb(0_0_0_/_0.1)] group  !opacity-100';

const actionButton
  = '!inline-flex !h-[26px] justify-center  px-2  gap-1 leading-5  whitespace-nowrap   focus-visible:shadow-none focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-primary disabled:cursor-not-allowed disabled:opacity-50 !bg-primary !text-primary-foreground ';

const cancelButton
  = '!inline-flex !h-[26px] justify-center px-2  gap-1 leading-5  whitespace-nowrap   focus-visible:shadow-none focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-primary disabled:cursor-not-allowed disabled:opacity-50 !border !border-border !bg-background !text-foreground active:shadow-[0_4px_6px_-1px_rgb(0_0_0_/_0.1),_0_2px_4px_-2px_rgb(0_0_0_/_0.1)]';

const description = 'text-sm !text-muted-foreground';

// Add !mt-0.5 to fix icon vertical alignment with title text
const icon
  = 'group-data-[type=success]:text-success group-data-[type=info]:text-info group-data-[type=warning]:text-warning group-data-[type=error]:text-destructive';

const title = 'text-sm font-medium';

const SonnerUI = (props: ToasterProps) => {
  const { theme = 'system' } = useTheme();

  const { expand = true, style = css as CSSProperties, toastOptions, ...rest } = props;

  return (
    <Sonner
      expand={expand}
      style={style}
      theme={theme as ToasterProps['theme']}
      toastOptions={{
        classNames: {
          actionButton: cn(actionButton, toastOptions?.classNames?.actionButton),
          cancelButton: cn(cancelButton, toastOptions?.classNames?.cancelButton),
          description: cn(description, toastOptions?.classNames?.description),
          icon: cn(icon, toastOptions?.classNames?.icon),
          title: cn(title, toastOptions?.classNames?.title),
          toast: cn(toastVariants, toastOptions?.classNames?.toast)
        }
      }}
      {...rest}
    />
  );
};

export default SonnerUI;

export { toast, useSonner } from 'sonner';

export { default as Sonner } from './InterSonner';

export * from './types';

// Message API - Lightweight global toast
export { message, default as Message } from './message';
export type { MessageConfig, MessageGlobalConfig, MessagePromiseData, MessageType } from './message';

// Notification API - Rich notification toast
export { notification, default as Notification } from './notification';
export type { ActionConfig, NotificationConfig, NotificationGlobalConfig, NotificationType } from './notification';

import type { ExternalToast, ToastT } from 'sonner';
import { toast } from 'sonner';

/**
 * Promise data configuration for message.promise()
 */
export interface MessagePromiseData<T = unknown> {
  /** Loading state message */
  loading?: React.ReactNode;
  /** Success state message or function that receives resolved data */
  success?: React.ReactNode | ((data: T) => React.ReactNode);
  /** Error state message or function that receives error */
  error?: React.ReactNode | ((error: unknown) => React.ReactNode);
  /** Callback when promise settles (success or error) */
  finally?: () => void | Promise<void>;
}

/**
 * Message configuration options
 * Lightweight global toast with icon and text only
 */
export interface MessageConfig {
  /** Message content */
  content?: React.ReactNode;
  /** Auto close delay in milliseconds. Set to 0 to disable auto close. Default: 3000ms */
  duration?: number;
  /** Callback when message closes */
  onClose?: () => void;
  /** Unique key for the message */
  key?: string | number;
  /** Custom icon */
  icon?: React.ReactNode;
  /** Custom inline style */
  style?: React.CSSProperties;
  /** Custom class name */
  className?: string;
  /** Display position. Default: top-center */
  position?: ToastT['position'];
}

export type MessageType = 'success' | 'error' | 'warning' | 'info' | 'loading';

/**
 * Global configuration options
 */
export interface MessageGlobalConfig {
  /** Default auto close delay in milliseconds. Default: 3000ms */
  duration?: number;
  /** Max message count. Oldest message will be closed when exceeded */
  maxCount?: number;
  /** Default position */
  position?: ToastT['position'];
}

// Message style class - compact
const messageClassName = '!py-2 !px-3 !min-h-0 !w-auto !max-w-md';

// Global config
let globalConfig: MessageGlobalConfig = {
  duration: 3000,
  position: 'top-center'
};

// Active messages tracking
const activeMessages = new Set<string | number>();

/**
 * Check if value is MessageConfig object
 */
function isMessageConfig(value: unknown): value is MessageConfig {
  return typeof value === 'object' && value !== null && 'content' in value;
}

/**
 * Show message toast
 */
function showMessage(
  type: MessageType,
  content: React.ReactNode | MessageConfig,
  duration?: number,
  onClose?: () => void
): string | number {
  // Support two calling methods:
  // 1. message.success('content', duration, onClose)
  // 2. message.success({ content: 'content', duration, onClose })
  let config: MessageConfig;

  if (isMessageConfig(content)) {
    config = content;
  }
  else {
    config = {
      content,
      duration,
      onClose
    };
  }

  const {
    content: messageContent,
    duration: msgDuration = globalConfig.duration,
    onClose: msgOnClose,
    key,
    icon,
    style,
    className,
    position = globalConfig.position
  } = config;

  // Check if max count exceeded
  if (globalConfig.maxCount && activeMessages.size >= globalConfig.maxCount) {
    // Close oldest message
    const firstKey = activeMessages.values().next().value;
    if (firstKey !== undefined) {
      toast.dismiss(firstKey);
      activeMessages.delete(firstKey);
    }
  }

  const toastOptions: ExternalToast = {
    id: key,
    duration: msgDuration,
    icon,
    style,
    className: `${messageClassName} ${className || ''}`.trim(),
    classNames: {
      title: '!font-normal'
    },
    position,
    onDismiss: () => {
      if (key) {
        activeMessages.delete(key);
      }
      msgOnClose?.();
    },
    onAutoClose: () => {
      if (key) {
        activeMessages.delete(key);
      }
      msgOnClose?.();
    }
  };

  let id: string | number;

  switch (type) {
    case 'success':
      id = toast.success(messageContent, toastOptions);
      break;
    case 'error':
      id = toast.error(messageContent, toastOptions);
      break;
    case 'warning':
      id = toast.warning(messageContent, toastOptions);
      break;
    case 'info':
      id = toast.info(messageContent, toastOptions);
      break;
    case 'loading':
      id = toast.loading(messageContent, toastOptions);
      break;
    default:
      id = toast(messageContent, toastOptions);
  }

  activeMessages.add(id);

  return id;
}

/**
 * Message API
 *
 * Display lightweight global feedback messages without interrupting user operations.
 *
 * @example
 * ```tsx
 * // Basic usage
 * message.success('Operation successful');
 * message.error('Operation failed');
 * message.warning('Warning message');
 * message.info('Info message');
 * message.loading('Loading...');
 *
 * // Custom duration (ms)
 * message.success('This message shows for 10s', 10000);
 *
 * // Using config object
 * message.success({
 *   content: 'Operation successful',
 *   duration: 5000,
 *   key: 'unique-key',
 *   onClose: () => console.log('closed')
 * });
 *
 * // Promise usage
 * message.promise(fetchData(), {
 *   loading: 'Loading...',
 *   success: 'Data loaded',
 *   error: 'Failed to load'
 * });
 *
 * // Manual dismiss
 * const id = message.loading('Loading...');
 * // ... async operation
 * message.dismiss(id);
 *
 * // Global config
 * message.config({ duration: 5000, maxCount: 3 });
 * ```
 */
export const message = {
  /**
   * Show success message
   */
  success(content: React.ReactNode | MessageConfig, duration?: number, onClose?: () => void) {
    return showMessage('success', content, duration, onClose);
  },

  /**
   * Show error message
   */
  error(content: React.ReactNode | MessageConfig, duration?: number, onClose?: () => void) {
    return showMessage('error', content, duration, onClose);
  },

  /**
   * Show warning message
   */
  warning(content: React.ReactNode | MessageConfig, duration?: number, onClose?: () => void) {
    return showMessage('warning', content, duration, onClose);
  },

  /**
   * Show info message
   */
  info(content: React.ReactNode | MessageConfig, duration?: number, onClose?: () => void) {
    return showMessage('info', content, duration, onClose);
  },

  /**
   * Show loading message
   */
  loading(content: React.ReactNode | MessageConfig, duration?: number, onClose?: () => void) {
    return showMessage('loading', content, duration, onClose);
  },

  /**
   * Show promise-based message with loading/success/error states
   */
  promise<T>(
    promise: Promise<T> | (() => Promise<T>),
    data: MessagePromiseData<T>,
    options?: Omit<MessageConfig, 'content'>
  ) {
    const { position = globalConfig.position, className, style, key, icon } = options || {};

    const toastOptions: ExternalToast = {
      id: key,
      icon,
      style,
      className: `${messageClassName} ${className || ''}`.trim(),
      classNames: {
        title: '!font-normal'
      },
      position
    };

    const result = toast.promise(promise, {
      loading: data.loading,
      success: data.success as string | React.ReactNode,
      error: data.error as string | React.ReactNode,
      finally: data.finally,
      ...toastOptions
    });

    return result;
  },

  /**
   * Open message with config
   */
  open(config: MessageConfig & { type?: MessageType }) {
    const { type = 'info', ...rest } = config;
    return showMessage(type, rest);
  },

  /**
   * Dismiss specific message or all messages
   */
  dismiss(id?: string | number) {
    if (id !== undefined) {
      activeMessages.delete(id);
    }
    else {
      activeMessages.clear();
    }
    return toast.dismiss(id);
  },

  /**
   * Alias for dismiss
   */
  destroy(id?: string | number) {
    return this.dismiss(id);
  },

  /**
   * Set global configuration
   */
  config(options: MessageGlobalConfig) {
    globalConfig = { ...globalConfig, ...options };
  }
};

export default message;

import type { ReactNode } from 'react';
import type { Action, ExternalToast, ToastT } from 'sonner';
import { toast } from 'sonner';

export type NotificationType = 'success' | 'error' | 'warning' | 'info';

/**
 * Notification configuration options
 * Toast notification with title, description, icon, and optional buttons
 */
export interface NotificationConfig {
  /** Notification title */
  title?: ReactNode;
  /** Notification description/content */
  description?: ReactNode;
  /** Auto close delay in milliseconds. Set to 0 to disable auto close. Default: 4500ms */
  duration?: number;
  /** Callback when notification closes */
  onClose?: () => void;
  /** Unique key for the notification */
  key?: string | number;
  /** Custom icon */
  icon?: ReactNode;
  /** Custom inline style */
  style?: React.CSSProperties;
  /** Custom class name */
  className?: string;
  /** Primary action button config */
  action?: ActionConfig | ReactNode;
  /** Cancel button config */
  cancel?: ActionConfig | ReactNode;
  /** Callback when notification is clicked */
  onClick?: () => void;
  /** Whether to show close button */
  closeButton?: boolean;
  /** Display position. Default: top-right */
  position?: ToastT['position'];
  /** Notification type */
  type?: NotificationType;
}

/**
 * Action button configuration
 */
export interface ActionConfig {
  /** Button label */
  label: ReactNode;
  /** Click callback */
  onClick: (event: React.MouseEvent<HTMLButtonElement, MouseEvent>) => void;
  /** Button style */
  style?: React.CSSProperties;
}

/**
 * Global configuration options
 */
export interface NotificationGlobalConfig {
  /** Default auto close delay in milliseconds. Default: 4500ms */
  duration?: number;
  /** Max notification count. Oldest notification will be closed when exceeded */
  maxCount?: number;
  /** Whether to show close button by default. Default: false */
  closeButton?: boolean;
  /** Default position */
  position?: ToastT['position'];
}

// Notification style class - wider and more prominent
// Use flex-wrap to let buttons flow to new line, content takes full width
// First button (cancel or action) gets ml-auto to push right, action gets ml-2 when after cancel
const notificationClassName = `
  !min-w-[320px] !max-w-[420px] !px-6 !py-5 !items-start
  !flex-wrap
  [&>[data-content]]:!w-[calc(100%-32px)]
  [&>[data-button]]:!mt-1
  [&>[data-cancel]]:!ml-auto
  [&>[data-cancel]+[data-action]]:!ml-2
  [&:not(:has([data-cancel]))>[data-action]]:!ml-auto
`.replace(/\s+/g, ' ').trim();

// Global config
let globalConfig: NotificationGlobalConfig = {
  duration: 4500,
  maxCount: undefined,
  closeButton: true,
  position: 'top-right'
};

// Active notifications tracking
const activeNotifications = new Set<string | number>();

/**
 * Convert ActionConfig to sonner Action
 */
function convertAction(action: ActionConfig | ReactNode | undefined): Action | ReactNode | undefined {
  if (!action)
    return undefined;

  if (typeof action === 'object' && 'label' in action && 'onClick' in action) {
    const actionConfig = action as ActionConfig;
    return {
      label: actionConfig.label,
      onClick: actionConfig.onClick,
      actionButtonStyle: actionConfig.style
    };
  }

  return action as ReactNode;
}

/**
 * Show notification toast
 */
function showNotification(
  type: NotificationType | 'default',
  config: NotificationConfig
): string | number {
  const {
    title,
    description,
    duration = globalConfig.duration,
    onClose,
    key,
    icon,
    style,
    className,
    action,
    cancel,
    onClick,
    closeButton = globalConfig.closeButton,
    position = globalConfig.position,
    ...rest
  } = config;

  // Check if max count exceeded
  if (globalConfig.maxCount && activeNotifications.size >= globalConfig.maxCount) {
    // Close oldest notification
    const firstKey = activeNotifications.values().next().value;
    if (firstKey !== undefined) {
      toast.dismiss(firstKey);
      activeNotifications.delete(firstKey);
    }
  }

  const toastOptions: ExternalToast = {
    id: key,
    description,
    duration,
    icon,
    style,
    className: `${notificationClassName} ${className || ''}`.trim(),
    action: convertAction(action),
    cancel: convertAction(cancel),
    closeButton,
    position,
    classNames: {
      title: '!text-base',
      description: '!mt-1.5',
      icon: '!mt-1'
    },
    onDismiss: () => {
      if (key) {
        activeNotifications.delete(key);
      }
      onClose?.();
    },
    onAutoClose: () => {
      if (key) {
        activeNotifications.delete(key);
      }
      onClose?.();
    },
    ...rest
  };

  let id: string | number;

  switch (type) {
    case 'success':
      id = toast.success(title, toastOptions);
      break;
    case 'error':
      id = toast.error(title, toastOptions);
      break;
    case 'warning':
      id = toast.warning(title, toastOptions);
      break;
    case 'info':
      id = toast.info(title, toastOptions);
      break;
    default:
      id = toast(title, toastOptions);
  }

  activeNotifications.add(id);

  return id;
}

/**
 * Notification API
 *
 * Display rich notification toasts with title, description, and optional actions.
 *
 * @example
 * ```tsx
 * // Basic usage
 * notification.success({
 *   title: 'Operation successful',
 *   description: 'Your changes have been saved'
 * });
 *
 * // With action buttons
 * notification.info({
 *   title: 'New message',
 *   description: 'You have a new message',
 *   action: {
 *     label: 'View',
 *     onClick: () => console.log('View')
 *   },
 *   cancel: {
 *     label: 'Ignore',
 *     onClick: () => console.log('Ignore')
 *   }
 * });
 *
 * // Custom duration (ms)
 * notification.warning({
 *   title: 'Warning',
 *   description: 'This notification shows for 10s',
 *   duration: 10000
 * });
 *
 * // Manual dismiss
 * const id = notification.info({ title: 'Notification' });
 * notification.dismiss(id);
 *
 * // With close button
 * notification.info({
 *   title: 'Notification',
 *   description: 'Click the close button to dismiss',
 *   closeButton: true
 * });
 *
 * // Global config
 * notification.config({ duration: 5000, maxCount: 3 });
 * ```
 */
export const notification = {
  /**
   * Show success notification
   */
  success(config: NotificationConfig) {
    return showNotification('success', config);
  },

  /**
   * Show error notification
   */
  error(config: NotificationConfig) {
    return showNotification('error', config);
  },

  /**
   * Show warning notification
   */
  warning(config: NotificationConfig) {
    return showNotification('warning', config);
  },

  /**
   * Show info notification
   */
  info(config: NotificationConfig) {
    return showNotification('info', config);
  },

  /**
   * Open notification with config
   */
  open(config: NotificationConfig & { type?: NotificationType }) {
    const { type = 'info', ...rest } = config;
    return showNotification(type, rest);
  },

  /**
   * Dismiss specific notification or all notifications
   */
  dismiss(id?: string | number) {
    if (id !== undefined) {
      activeNotifications.delete(id);
    }
    else {
      activeNotifications.clear();
    }
    return toast.dismiss(id);
  },

  /**
   * Alias for dismiss
   */
  destroy(id?: string | number) {
    return this.dismiss(id);
  },

  /**
   * Set global configuration
   */
  config(options: NotificationGlobalConfig) {
    globalConfig = { ...globalConfig, ...options };
  }
};

export default notification;
